import { useState } from "react";
import axios from "axios";

function Chatbot() {

    const [question, setQuestion] = useState("");
    const [response, setResponse] = useState("");

    const handleSend = async () => {

        if (question.toLowerCase().includes("weather")) {

            const res = await axios.get(
                "https://api.open-meteo.com/v1/forecast?latitude=11.0168&longitude=76.9558&current_weather=true"
            );

            const temp = res.data.current_weather.temperature;

            setResponse(`Today's temperature is ${temp}°C. Stay prepared for climate conditions.`);

        } else {

            setResponse("Ask about climate, weather, or sustainability.");

        }

    };

    return (
        <div className="page">

            <h1>AI Climate Chatbot</h1>

            <div className="chat-box">
                <p>{response}</p>
            </div>

            <input
                type="text"
                placeholder="Ask climate question"
                value={question}
                onChange={(e) => setQuestion(e.target.value)}
            />

            <button onClick={handleSend}>Send</button>

        </div>
    );
}

export default Chatbot;
